@RestController @RequestMapping("/api/alarms") class AlarmController extends CrudController<Alarm>{ final PlatformCoreService s; AlarmController(AlarmDao r, CrudService<Alarm> c, PlatformCoreService s){super(r,c);this.s=s;} @Override @GetMapping ApiResponse<Object> list(@RequestParam Map<String,String> q){return ApiResponse.ok(q.containsKey("page")||q.containsKey("size")?s.alarmPage(q):service.list(dao,q.get("keyword")));} @GetMapping("/stats") ApiResponse<Map<String,Object>> stats(@RequestParam Map<String,String> q){return ApiResponse.ok(s.alarmStats(q));} @PostMapping("/{id}/handle") ApiResponse<Alarm> handle(@PathVariable Long id,@RequestBody Map<String,Object>b){return ApiResponse.ok(s.handleAlarm(id,b));} @PostMapping("/{id}/status") ApiResponse<Alarm> status(@PathVariable Long id,@RequestBody Map<String,Object>b){return ApiResponse.ok(s.updateAlarmStatus(id,String.valueOf(b.getOrDefault("status","CLOSED")),b));} @PostMapping("/{id}/close") ApiResponse<Alarm> close(@PathVariable Long id){return ApiResponse.ok(s.handleAlarm(id,Map.of("remark","关闭告警")));} }
@RestController @RequestMapping("/api/tasks") class TaskController extends CrudController<TaskJob>{ final PlatformCoreService s; TaskController(TaskJobDao r, CrudService<TaskJob> c, PlatformCoreService s){super(r,c);this.s=s;} @PostMapping("/{id}/start") ApiResponse<TaskJob> start(@RequestHeader(value="X-User-Name",required=false) String operator,@PathVariable Long id){return ApiResponse.ok(s.switchTask(id,true,operator));} @PostMapping("/{id}/stop") ApiResponse<TaskJob> stop(@RequestHeader(value="X-User-Name",required=false) String operator,@PathVariable Long id){return ApiResponse.ok(s.switchTask(id,false,operator));} @GetMapping("/logs") ApiResponse<List<TaskLog>> logs(){return ApiResponse.ok(s.taskLogs());} }
@RestController @RequestMapping("/api/network-services") class NetworkServiceController extends CrudController<NetworkService>{ final MqttTelemetrySubscriber mqtt; final PlatformCoreService s; NetworkServiceController(NetworkServiceDao r, CrudService<NetworkService> c, MqttTelemetrySubscriber mqtt,PlatformCoreService s){super(r,c);this.mqtt=mqtt;this.s=s;} @Override @PostMapping("/{id}/toggle") ApiResponse<NetworkService> toggle(@PathVariable Long id){NetworkService old=((NetworkServiceDao)dao).findById(id).orElseThrow();old.status="RUNNING".equals(old.status)?"STOPPED":"RUNNING";NetworkService saved=dao.save(old);if("mqtt-server".equals(saved.code))mqtt.applyNetworkServiceStatus(saved.status);s.op("网络服务","RUNNING".equals(saved.status)?"启动服务":"停止服务","admin",saved.name);return ApiResponse.ok(saved);} @PostMapping("/{id}/start") ApiResponse<NetworkService> start(@PathVariable Long id){NetworkService saved=service.status(dao,id,"RUNNING");if("mqtt-server".equals(saved.code))mqtt.applyNetworkServiceStatus(saved.status);return ApiResponse.ok(saved);} @PostMapping("/{id}/stop") ApiResponse<NetworkService> stop(@PathVariable Long id){NetworkService saved=service.status(dao,id,"STOPPED");if("mqtt-server".equals(saved.code))mqtt.applyNetworkServiceStatus(saved.status);return ApiResponse.ok(saved);} }
@RestController @RequestMapping("/api/firmwares") class FirmwareController extends CrudController<Firmware>{ FirmwareController(FirmwareDao r, CrudService<Firmware> c){super(r,c);} @PostMapping("/{id}/upgrade") ApiResponse<Firmware> upgrade(@PathVariable Long id,@RequestBody(required=false) Map<String,Object>b){ Firmware f=dao.findById(id).orElseThrow(); f.upgradeStatus= b==null?"UPGRADING":String.valueOf(b.getOrDefault("status","UPGRADING")); f.status=f.upgradeStatus; return ApiResponse.ok(dao.save(f)); } }
@RestController @RequestMapping("/api/ai-agents") class AiAgentController extends CrudController<AiAgent>{ final PlatformCoreService s; AiAgentController(AiAgentDao r, CrudService<AiAgent> c, PlatformCoreService s){super(r,c);this.s=s;} @PostMapping("/chat") ApiResponse<Map<String,Object>> chat(@RequestHeader(value="X-User-Name",required=false) String operator,@RequestBody Map<String,Object> b){b.put("operator",operator);return ApiResponse.ok(s.aiChat(b));} @PostMapping("/models") ApiResponse<Map<String,Object>> models(@RequestHeader(value="X-User-Name",required=false) String operator,@RequestBody(required=false) Map<String,Object> b){Map<String,Object> body=b==null?new LinkedHashMap<>():new LinkedHashMap<>(b);body.put("operator",operator);return ApiResponse.ok(s.aiModels(body));} }
@RestController @RequestMapping("/api/users") class UserController extends CrudController<SysUser>{ UserController(UserDao r, CrudService<SysUser> c){super(r,c);} @PostMapping("/password") ApiResponse<Boolean> password(@RequestHeader(value="X-User-Name",required=false) String username,@RequestBody Map<String,String> body){if(username==null||username.isBlank())throw new RuntimeException("当前用户不存在");SysUser user=((UserDao)dao).findByUsername(username);if(user==null)throw new RuntimeException("当前用户不存在");if(!Objects.equals(user.password,body.get("oldPassword")))throw new RuntimeException("原密码错误");String next=body.get("newPassword");if(next==null||next.length()<6)throw new RuntimeException("新密码至少6位");user.password=next;dao.save(user);return ApiResponse.ok(true);} @Override @PostMapping ApiResponse<SysUser> create(@RequestBody SysUser body){ if (body.password == null || body.password.isBlank()) body.password="123456"; return ApiResponse.ok(dao.save(body)); } @Override @PutMapping("/{id}") ApiResponse<SysUser> update(@PathVariable Long id,@RequestBody SysUser body){ SysUser old=((UserDao)dao).findById(id).orElseThrow(); if (body.password == null || body.password.isBlank()) body.password=null; return ApiResponse.ok(dao.save(CrudSupport.merge(old,body))); } }
@RestController @RequestMapping("/api/roles") class RoleController extends CrudController<Role>{ RoleController(RoleDao r, CrudService<Role> c){super(r,c);} }
@RestController @RequestMapping("/api/device-attributes") class DeviceAttributeController extends CrudController<DeviceAttribute>{ DeviceAttributeController(DeviceAttributeDao r, CrudService<DeviceAttribute> c){super(r,c);} @Override @PostMapping ApiResponse<DeviceAttribute> create(@RequestBody DeviceAttribute body){normalize(body);validate(body,null);return super.create(body);}@Override @PutMapping("/{id}") ApiResponse<DeviceAttribute> update(@PathVariable Long id,@RequestBody DeviceAttribute body){normalize(body);validate(body,id);return super.update(id,body);} void validate(DeviceAttribute body,Long id){if(blank(body.name))throw new IllegalArgumentException("属性名不能为空");DeviceAttribute same=((DeviceAttributeDao)dao).findByName(body.name);if(same!=null&&!Objects.equals(same.id,id))throw new IllegalArgumentException("属性名不能重复");String type=type(body);if(!List.of("BOOL","INT","FLOAT","STRING").contains(type))throw new IllegalArgumentException("属性类型不能为空");if(Boolean.TRUE.equals(body.minEnabled)&&Boolean.TRUE.equals(body.maxEnabled)&&body.minValue!=null&&body.maxValue!=null&&body.minValue>body.maxValue)throw new IllegalArgumentException("最小值不能大于最大值");} void normalize(DeviceAttribute body){body.valueType=type(body);if(Boolean.TRUE.equals(body.rangeEnabled)){body.minEnabled=body.minEnabled==null?true:body.minEnabled;body.maxEnabled=body.maxEnabled==null?true:body.maxEnabled;}if(!List.of("INT","FLOAT").contains(body.valueType)){body.rangeEnabled=false;body.minEnabled=false;body.maxEnabled=false;body.minValue=null;body.maxValue=null;return;}body.minEnabled=Boolean.TRUE.equals(body.minEnabled);body.maxEnabled=Boolean.TRUE.equals(body.maxEnabled);body.rangeEnabled=body.minEnabled||body.maxEnabled;if(!body.minEnabled)body.minValue=null;if(!body.maxEnabled)body.maxValue=null;} String type(DeviceAttribute body){String raw=body.valueType==null?"":body.valueType.trim().toUpperCase();return Map.of("BOOLEAN","BOOL","布尔型","BOOL","整型","INT","浮点型","FLOAT","字符型","STRING").getOrDefault(raw,raw);} boolean blank(String value){return value==null||value.isBlank();} }
@RestController @RequestMapping("/api/product-categories") class ProductCategoryController extends CrudController<ProductCategory>{ ProductCategoryController(ProductCategoryDao r, CrudService<ProductCategory> c){super(r,c);} @Override @PostMapping ApiResponse<ProductCategory> create(@RequestBody ProductCategory body){validate(body);return super.create(body);}@Override @PutMapping("/{id}") ApiResponse<ProductCategory> update(@PathVariable Long id,@RequestBody ProductCategory body){validate(body);return super.update(id,body);} void validate(ProductCategory body){if(blank(body.name))throw new IllegalArgumentException("分类名称不能为空");if(blank(body.code))throw new IllegalArgumentException("分类编码不能为空");} boolean blank(String value){return value==null||value.isBlank();} }
@RestController @RequestMapping("/api/products") class ProductController extends CrudController<Product>{ ProductController(ProductDao r, CrudService<Product> c){super(r,c);} @Override @PostMapping ApiResponse<Product> create(@RequestBody Product body){normalizeRules(body);validate(body);return super.create(body);}@Override @PutMapping("/{id}") ApiResponse<Product> update(@PathVariable Long id,@RequestBody Product body){normalizeRules(body);validate(body);return super.update(id,body);} void normalizeRules(Product body){if(!blank(body.ruleIds)&&body.ruleId==null){String first=body.ruleIds.split(",")[0].trim();if(!first.isBlank())body.ruleId=Long.valueOf(first);}} void validate(Product body){if(blank(body.name))throw new IllegalArgumentException("产品名称不能为空");if(blank(body.code))throw new IllegalArgumentException("产品编码不能为空");if(body.categoryId==null)throw new IllegalArgumentException("所属分类不能为空");if(body.ruleId==null&&blank(body.ruleIds))throw new IllegalArgumentException("规则链不能为空");if(blank(body.protocol))throw new IllegalArgumentException("接入协议不能为空");} boolean blank(String value){return value==null||value.isBlank();} }
@RestController @RequestMapping("/api/device-groups") class DeviceGroupController extends CrudController<DeviceGroup>{ DeviceGroupController(DeviceGroupDao r, CrudService<DeviceGroup> c){super(r,c);} @Override @PostMapping ApiResponse<DeviceGroup> create(@RequestBody DeviceGroup body){validate(body);return super.create(body);}@Override @PutMapping("/{id}") ApiResponse<DeviceGroup> update(@PathVariable Long id,@RequestBody DeviceGroup body){validate(body);return super.update(id,body);} void validate(DeviceGroup body){if(blank(body.name))throw new IllegalArgumentException("分组名称不能为空");if(blank(body.code))throw new IllegalArgumentException("分组编码不能为空");if(blank(body.location))throw new IllegalArgumentException("位置不能为空");if(blank(body.owner))throw new IllegalArgumentException("负责人不能为空");if(body.deviceCount==null)throw new IllegalArgumentException("设备数不能为空");if(blank(body.attributeIds))throw new IllegalArgumentException("设备属性不能为空");} boolean blank(String value){return value==null||value.isBlank();} }
@RestController @RequestMapping("/api/devices") class DeviceController extends CrudController<Device>{ final PlatformCoreService s; DeviceController(DeviceDao r, CrudService<Device> c,PlatformCoreService s){super(r,c);this.s=s;} @Override @GetMapping ApiResponse<Object> list(@RequestParam Map<String,String> q){s.refreshDeviceStatuses();return ApiResponse.ok(service.list(dao,q.get("keyword")));} @Override @PostMapping ApiResponse<Device> create(@RequestBody Device body){validate(body);return super.create(body);}@Override @PutMapping("/{id}") ApiResponse<Device> update(@PathVariable Long id,@RequestBody Device body){validate(body);return super.update(id,body);} void validate(Device body){if(blank(body.name))throw new IllegalArgumentException("设备名称不能为空");if(blank(body.code))throw new IllegalArgumentException("设备编码不能为空");if(body.productId==null)throw new IllegalArgumentException("所属产品不能为空");if(body.groupId==null)throw new IllegalArgumentException("所属分组不能为空");if(blank(body.deviceKey))throw new IllegalArgumentException("设备 Key 不能为空");if(body.temperature==null)throw new IllegalArgumentException("当前温度不能为空");if(blank(body.location))throw new IllegalArgumentException("位置不能为空");if(body.latitude==null)throw new IllegalArgumentException("纬度不能为空");if(body.longitude==null)throw new IllegalArgumentException("经度不能为空");} boolean blank(String value){return value==null||value.isBlank();} }
@RestController @RequestMapping("/api/rules") class RuleController extends CrudController<Rule>{ final AlarmDao alarms; final DeviceAttributeDao attributes; RuleController(RuleDao r, CrudService<Rule> c, AlarmDao alarms,DeviceAttributeDao attributes){super(r,c);this.alarms=alarms;this.attributes=attributes;} @Override @PostMapping ApiResponse<Rule> create(@RequestBody Rule body){normalize(body);validate(body);return super.create(body);}@Override @PutMapping("/{id}") ApiResponse<Rule> update(@PathVariable Long id,@RequestBody Rule body){normalize(body);validate(body);Rule old=((RuleDao)dao).findById(id).orElseThrow();Rule saved=service.update(dao,id,body);alarms.findAll().stream().filter(a->Objects.equals(a.ruleId,id)||(a.ruleId==null&&Objects.equals(a.ruleName,old.name))).forEach(a->{a.ruleId=id;a.ruleName=saved.name;a.level=saved.alarmLevel;alarms.save(a);});return ApiResponse.ok(saved);} void normalize(Rule body){body.logicOperator=logic(body.logicOperator);body.operator=operator(body.operator);body.threshold=threshold(body.threshold);body.secondOperator=operator(body.secondOperator);body.secondThreshold=threshold(body.secondThreshold);if(blank(body.logicOperator)){body.secondMetric=null;body.secondOperator=null;body.secondThreshold=null;}} void validate(Rule body){if(blank(body.name))throw new IllegalArgumentException("规则名称不能为空");validateCondition(body.metric,body.operator,body.threshold,"第一条件");if(!blank(body.logicOperator))validateCondition(body.secondMetric,body.secondOperator,body.secondThreshold,"第二条件");if(blank(body.alarmLevel))throw new IllegalArgumentException("告警等级不能为空");if(blank(body.action))throw new IllegalArgumentException("触发动作不能为空");} void validateCondition(String metric,String operator,String threshold,String label){if(blank(metric))throw new IllegalArgumentException(label+"数据指标不能为空");DeviceAttribute attr=attributes.findByName(metric);if(attr==null)throw new IllegalArgumentException(label+"数据指标必须从设备属性中选择");String type=attr.valueType==null?"":attr.valueType.trim().toUpperCase();if(blank(operator))throw new IllegalArgumentException(label+"判断条件不能为空");if("BOOL".equals(type)){if(!List.of("==","!=").contains(operator))throw new IllegalArgumentException(label+"布尔类型只支持等于和不等于");if(!List.of("True","False").contains(threshold))throw new IllegalArgumentException(label+"布尔阈值必须选择 True 或 False");return;}if("STRING".equals(type)){if(!List.of("==","!=").contains(operator))throw new IllegalArgumentException(label+"字符型只支持等于和不等于");if(threshold==null)throw new IllegalArgumentException(label+"阈值不能为空");return;}if(!List.of("INT","FLOAT").contains(type))throw new IllegalArgumentException(label+"属性类型不支持规则判断");if(!List.of(">",">=","<","<=","==","!=").contains(operator))throw new IllegalArgumentException(label+"判断条件不支持");Double value;try{value=Double.valueOf(threshold);}catch(Exception e){throw new IllegalArgumentException(label+"阈值必须是数字");}if("INT".equals(type)&&value.doubleValue()!=Math.rint(value))throw new IllegalArgumentException(label+"整型阈值必须是整数");if(!conditionPossible(attr,operator,value))throw new IllegalArgumentException(label+"与设备属性范围无交集，无法建立规则");} boolean conditionPossible(DeviceAttribute attr,String op,double threshold){if(!("INT".equals(attr.valueType)||"FLOAT".equals(attr.valueType)))return true;boolean minActive=Boolean.TRUE.equals(attr.minEnabled)||(attr.minEnabled==null&&Boolean.TRUE.equals(attr.rangeEnabled));boolean maxActive=Boolean.TRUE.equals(attr.maxEnabled)||(attr.maxEnabled==null&&Boolean.TRUE.equals(attr.rangeEnabled));Double min=minActive?attr.minValue:null;Double max=maxActive?attr.maxValue:null;return switch(op){case ">"->max==null||max>threshold;case ">="->max==null||max>=threshold;case "<"->min==null||min<threshold;case "<="->min==null||min<=threshold;case "=="->(min==null||threshold>=min)&&(max==null||threshold<=max);case "!="->min==null||max==null||Double.compare(min,max)!=0||Double.compare(min,threshold)!=0;default->true;};} String operator(String value){String raw=value==null?"":value.trim();return List.of(">",">=","<","<=","==","!=").contains(raw)?raw:"";} String threshold(String value){return value==null?null:value.trim();} String logic(String value){String raw=value==null?"":value.trim().toUpperCase();return List.of("AND","OR").contains(raw)?raw:"";} boolean blank(String value){return value==null||value.isBlank();} }
