abstract class CrudController<T extends BaseEntity> { final JpaRepository<T,Long> dao; final CrudService<T> service; CrudController(JpaRepository<T,Long> dao, CrudService<T> service){this.dao=dao;this.service=service;} @GetMapping ApiResponse<Object> list(@RequestParam Map<String,String> q){ return ApiResponse.ok(service.list(dao, q.get("keyword"))); } @GetMapping("/{id}") ApiResponse<T> get(@PathVariable Long id){ return ApiResponse.ok(service.get(dao,id)); } @PostMapping ApiResponse<T> create(@RequestBody T body){ return ApiResponse.ok(service.create(dao,body)); } @PutMapping("/{id}") ApiResponse<T> update(@PathVariable Long id,@RequestBody T body){ return ApiResponse.ok(service.update(dao,id,body)); } @DeleteMapping("/{id}") ApiResponse<Boolean> delete(@PathVariable Long id){ return ApiResponse.ok(service.delete(dao,id)); } @PostMapping("/{id}/toggle") ApiResponse<T> toggle(@PathVariable Long id){ return ApiResponse.ok(service.toggle(dao,id)); } ApiResponse<T> status(Long id,String status){ return ApiResponse.ok(service.status(dao,id,status)); } }
